const DEFAULT_GITLAB_API_BASE_URL: &str = "https://gitlab.com/api/v4";
const DEFAULT_FORGEJO_API_BASE_URL: &str = "https://codeberg.org/api/v1";

#[derive(Debug, Clone, Copy)]
struct GitBackendOptions<'a> {
    values: BackendOptions<'a>,
