}

impl<'a> GitBackendOptions<'a> {
    fn new(raw: &'a ToolVersionOptions, default_api_url: &'static str) -> Self {
        Self {
            values: BackendOptions::new(raw),
            default_api_url,
        }
    }

    fn raw(&self) -> &'a ToolVersionOptions {
        self.values.raw()
    }

    fn api_url(&self) -> String {
        self.values
            .str("api_url")
