    #[test]
    fn test_resolve_token_wrapper_uses_github_tokens_toml_source() {
        // Proves the wrapper delegates all the way through `resolve_token` to the
        // non-env-var sources — here, the `github_tokens.toml` path (source #4). Without
        // this, a future regression could short-circuit on env vars and silently pass all
        // prior tests.
        let _lock = crate::github::TEST_ENV_LOCK.lock().unwrap();
        let _env = TokenEnvGuard::new();
        let _tokens_file = TokensFileOverrideGuard::set("github.com", "ghp_from_tokens_file");

        let resolved = resolve_token_for_wrapper(None);
        assert_eq!(
            resolved.as_deref(),
            Some("ghp_from_tokens_file"),
            "wrapper should resolve tokens from github_tokens.toml when env vars are empty"
        );
    }

    // =========================================================================
    // Archive-aware (inner-file) attestation verification
    //
    // These tests pin the fail-closed policy without touching the network: the
    // decision core is exercised through a mock verifier and a real crafted
    // `.tar.gz`/`.zip`, covering (a) when the fallback is allowed to run, (b)
    // the "every regular inner file must be attested" rule, and (c) extraction
    // returning only regular files (symlinks excluded).
    // =========================================================================

    use std::io::{Cursor, Write};

    enum TestEntry<'a> {
        File(&'a str, &'a [u8]),
        /// A symlink entry: `(link_path, target_path)`.
        Symlink(&'a str, &'a str),
    }

    /// Build `payload.tar.gz` in `workdir` containing the given entries. Regular
    /// files with paths containing `/` produce nested files (parents are created
    /// on extraction); symlink entries are emitted as symlinks.
    fn build_targz(workdir: &Path, entries: &[TestEntry<'_>]) -> PathBuf {
        let tar_path = workdir.join("payload.tar.gz");
        let f = std::fs::File::create(&tar_path).unwrap();
        let gz = flate2::write::GzEncoder::new(f, flate2::Compression::default());
        let mut builder = tar::Builder::new(gz);
        for entry in entries {
            match entry {
                TestEntry::File(name, content) => {
                    let mut header = tar::Header::new_gnu();
                    header.set_size(content.len() as u64);
                    header.set_mode(0o644);
                    header.set_entry_type(tar::EntryType::Regular);
                    header.set_mtime(0);
                    header.set_cksum();
                    builder
                        .append_data(&mut header, *name, Cursor::new(*content))
                        .unwrap();
                }
                TestEntry::Symlink(name, target) => {
                    let mut header = tar::Header::new_gnu();
                    header.set_size(0);
                    header.set_mode(0o777);
                    header.set_entry_type(tar::EntryType::Symlink);
                    header.set_link_name(*target).unwrap();
                    header.set_mtime(0);
                    header.set_cksum();
                    builder
                        .append_data(&mut header, *name, Cursor::new(&[][..]))
                        .unwrap();
                }
            }
        }
        builder.finish().unwrap();
        tar_path
    }

    /// Mock verifier that identifies the archive by its file name
    /// (`payload.tar.gz`) and dispatches inner files via `inner`. Avoids
    /// capturing any comparison path so the closure stays `Fn` with a
    /// self-contained future type.
    fn mock_verifier(
        inner: impl Fn(&Path) -> AttestationResult<bool> + Copy + 'static,
    ) -> impl FnMut(&Path) -> std::pin::Pin<std::boxed::Box<dyn std::future::Future<Output = AttestationResult<bool>> + Send>> {
        // Unused: kept for documentation of the closure-return approach.
        let _ = inner;
        unreachable!("helper superseded by inline closures")
    }

    #[tokio::test]
    async fn archive_aware_accepts_when_all_inner_files_attested() {
        let dir = tempfile::tempdir().unwrap();
        let archive = build_targz(
            dir.path(),
            &[
                TestEntry::File("bin/tool", b"binary-bytes"),
                TestEntry::File("README.md", b"docs"),
            ],
        );
        // Archive blob has NO attestation; every inner file is attested.
        let verifier = |p: &Path| {
            let p = p.to_path_buf();
            Box::pin(async move {
                if p.file_name().map(|n| n == "payload.tar.gz").unwrap_or(false) {
                    Err(AttestationError::NoAttestations)
                } else {
                    Ok(true)
                }
            })
                as std::pin::Pin<std::boxed::Box<dyn std::future::Future<Output = _> + Send>>
        };
        let result = verify_archive_aware_with_verifier(&archive, verifier).await;
        assert!(matches!(result, Ok(true)), "expected Ok(true), got {result:?}");
    }

    #[tokio::test]
    async fn archive_aware_rejects_unattested_inner_file() {
        let dir = tempfile::tempdir().unwrap();
        let archive = build_targz(
            dir.path(),
            &[
                TestEntry::File("bin/tool", b"binary-bytes"),
                TestEntry::File("README.md", b"docs"),
            ],
        );
        // bin/tool attested, README.md is NOT — must fail closed regardless of
        // walk order.
        let verifier = |p: &Path| {
            let p = p.to_path_buf();
            Box::pin(async move {
                if p.file_name().map(|n| n == "payload.tar.gz").unwrap_or(false) {
                    Err(AttestationError::NoAttestations)
                } else if p.file_name().map(|n| n == "tool").unwrap_or(false) {
                    Ok(true)
                } else {
                    Err(AttestationError::NoAttestations)
                }
            })
                as std::pin::Pin<std::boxed::Box<dyn std::future::Future<Output = _> + Send>>
        };
        let result = verify_archive_aware_with_verifier(&archive, verifier).await;
        let err = result.unwrap_err().to_string();
        assert!(
            err.contains("no GitHub artifact attestation"),
            "expected fail-closed unattested-file error, got {err}"
        );
    }

    #[tokio::test]
    async fn archive_aware_does_not_fall_back_on_real_archive_failure() {
        // Attestations EXIST for the archive blob but fail to verify. This must
        // surface the error directly — never fall back to inner files.
        let dir = tempfile::tempdir().unwrap();
        let archive = build_targz(dir.path(), &[TestEntry::File("bin/tool", b"x")]);
        let verifier = |p: &Path| {
            let p = p.to_path_buf();
            Box::pin(async move {
                if p.file_name().map(|n| n == "payload.tar.gz").unwrap_or(false) {
                    Err(AttestationError::Verification("bad archive sig".to_string()))
                } else {
                    // If the fallback ran, inner files would "verify" and mask the
                    // archive failure — the assertion below catches that.
                    Ok(true)
                }
            })
                as std::pin::Pin<std::boxed::Box<dyn std::future::Future<Output = _> + Send>>
        };
        let result = verify_archive_aware_with_verifier(&archive, verifier).await;
        let err = result.unwrap_err().to_string();
        assert!(
            err.contains("bad archive sig"),
            "archive verification failure must propagate without fallback, got {err}"
        );
    }

    #[tokio::test]
    async fn archive_aware_accepts_archive_level_without_fallback() {
        // Archive blob verifies on its own. Inner files would fail; if the
        // fallback incorrectly ran, the test would fail.
        let dir = tempfile::tempdir().unwrap();
        let archive = build_targz(dir.path(), &[TestEntry::File("bin/tool", b"x")]);
        let verifier = |p: &Path| {
            let p = p.to_path_buf();
            Box::pin(async move {
                if p.file_name().map(|n| n == "payload.tar.gz").unwrap_or(false) {
                    Ok(true)
                } else {
                    Err(AttestationError::NoAttestations)
                }
            })
                as std::pin::Pin<std::boxed::Box<dyn std::future::Future<Output = _> + Send>>
        };
        let result = verify_archive_aware_with_verifier(&archive, verifier).await;
        assert!(matches!(result, Ok(true)), "expected Ok(true), got {result:?}");
    }

    #[tokio::test]
    async fn archive_aware_non_archive_preserves_no_attestations() {
        // A raw binary (not a multi-file archive) must return NoAttestations so
        // the caller's SLSA/unavailable fallback runs unchanged.
        let dir = tempfile::tempdir().unwrap();
        let bin = dir.path().join("tool.bin");
        std::fs::write(&bin, b"raw-binary").unwrap();
        let verifier = |p: &Path| {
            assert!(p.file_name().map(|n| n == "tool.bin").unwrap_or(false));
            Box::pin(async { Err(AttestationError::NoAttestations) })
                as std::pin::Pin<std::boxed::Box<dyn std::future::Future<Output = _> + Send>>
        };
        let result = verify_archive_aware_with_verifier(&bin, verifier).await;
        assert!(
            matches!(result, Err(AttestationError::NoAttestations)),
            "non-archive must surface NoAttestations, got {result:?}"
        );
    }

    #[test]
    fn extract_regular_files_skips_symlinks_and_includes_nested() {
        let dir = tempfile::tempdir().unwrap();
        let archive = build_targz(
            dir.path(),
            &[
                TestEntry::File("top.txt", b"top"),
                TestEntry::File("sub/nested.txt", b"nested"),
                TestEntry::Symlink("link", "top.txt"),
            ],
        );
        let (_guard, files) = extract_regular_files(&archive, TarFormat::TarGz).unwrap();
        let names: Vec<String> = files
            .iter()
            .map(|p| p.file_name().unwrap().to_string_lossy().to_string())
            .collect();
        assert!(names.contains(&"top.txt".to_string()), "missing top.txt: {names:?}");
        assert!(
            names.contains(&"nested.txt".to_string()),
            "missing nested.txt: {names:?}"
        );
        assert!(
            !names.contains(&"link".to_string()),
            "symlink must never be attested: {names:?}"
        );
        assert_eq!(names.len(), 2, "expected exactly 2 regular files: {names:?}");
    }

    #[test]
    fn extract_regular_files_handles_zip() {
        let dir = tempfile::tempdir().unwrap();
        let zip_path = dir.path().join("payload.zip");
        {
            let f = std::fs::File::create(&zip_path).unwrap();
            let mut zip = zip::ZipWriter::new(f);
            let opts = zip::write::SimpleFileOptions::default();
            zip.start_file("a.txt", opts).unwrap();
            zip.write_all(b"a").unwrap();
            zip.start_file("dir/b.txt", opts).unwrap();
            zip.write_all(b"b").unwrap();
            zip.finish().unwrap();
        }
        let (_guard, files) = extract_regular_files(&zip_path, TarFormat::Zip).unwrap();
        let names: Vec<String> = files
            .iter()
            .map(|p| p.file_name().unwrap().to_string_lossy().to_string())
            .collect();
        assert!(names.contains(&"a.txt".to_string()));
        assert!(names.contains(&"b.txt".to_string()));
        assert_eq!(names.len(), 2, "expected exactly 2 regular files: {names:?}");
    }

    #[test]
    fn reduce_accepts_all_verified() {
        let files = vec![PathBuf::from("a"), PathBuf::from("b")];
        assert!(matches!(
            reduce_inner_outcomes(&files, vec![Ok(true), Ok(true)]),
            Ok(true)
        ));
    }

    #[test]
    fn reduce_rejects_unattested() {
        let files = vec![PathBuf::from("a")];
        let err = reduce_inner_outcomes(&files, vec![Err(AttestationError::NoAttestations)])
            .unwrap_err()
            .to_string();
        assert!(err.contains("no GitHub artifact attestation"), "got {err}");
    }

    #[test]
    fn reduce_rejects_false_outcome() {
        let files = vec![PathBuf::from("a")];
        let err = reduce_inner_outcomes(&files, vec![Ok(false)])
            .unwrap_err()
            .to_string();
        assert!(err.contains("did not verify"), "got {err}");
    }

    #[test]
    fn reduce_propagates_other_errors() {
        let files = vec![PathBuf::from("a")];
        let err = reduce_inner_outcomes(&files, vec![Err(AttestationError::Api("boom".to_string()))])
            .unwrap_err()
            .to_string();
        assert!(err.contains("boom"), "got {err}");
    }

    #[test]
    fn reduce_first_terminal_wins() {
        // a is unattested (terminal) even though b verifies — must fail, not pass.
        let files = vec![PathBuf::from("a"), PathBuf::from("b")];
        let result = reduce_inner_outcomes(&files, vec![Err(AttestationError::NoAttestations), Ok(true)]);
        assert!(result.is_err(), "expected fail-closed, got {result:?}");
    }

    /// Compile-time / documentation helper kept out of the way; never called.
    #[allow(dead_code)]
    fn _unused_mock_verifier_doc(_: impl Fn(&Path) -> AttestationResult<bool> + Copy + 'static) {
        mock_verifier(|_| Ok(true));
    }
}

