    /// Build `payload.tar.gz` in `workdir` containing the given entries. Regular
    /// files with paths containing `/` produce nested files (parents are created
    /// on extraction); symlink entries are emitted as symlinks.
    fn build_targz(workdir: &Path, entries: &[TestEntry<'_>]) -> PathBuf {
        let tar_path = workdir.join("payload.tar.gz");
        let f = std::fs::File::create(&tar_path).unwrap();
        let gz = flate2::write::GzEncoder::new(f, flate2::Compression::default());
        let mut builder = tar::Builder::new(gz);
        for entry in entries {
            match entry {
                TestEntry::File(name, content) => {
                    let mut header = tar::Header::new_gnu();
                    header.set_size(content.len() as u64);
                    header.set_mode(0o644);
                    header.set_entry_type(tar::EntryType::Regular);
                    header.set_mtime(0);
                    header.set_cksum();
                    builder
                        .append_data(&mut header, *name, Cursor::new(*content))
                        .unwrap();
                }
                TestEntry::Symlink(name, target) => {
                    let mut header = tar::Header::new_gnu();
                    header.set_size(0);
                    header.set_mode(0o777);
                    header.set_entry_type(tar::EntryType::Symlink);
                    header.set_link_name(*target).unwrap();
                    header.set_mtime(0);
                    header.set_cksum();
                    builder
                        .append_data(&mut header, *name, Cursor::new(&[][..]))
                        .unwrap();
