/// Classify one inner file's attestation outcome into a terminal result for the
/// whole archive, or `None` to continue to the next file.
///
/// This is the single source of truth for the per-file fail-closed rule used by
/// [`verify_archive_aware_with_verifier`] in strict mode (and exercised directly
/// in tests).
fn classify_inner_outcome(
    file: &Path,
    outcome: AttestationResult<bool>,
) -> Option<AttestationResult<bool>> {
    match outcome {
        Ok(true) => None,
        // The sigstore primitives never return Ok(false) today, but treat it as
        // a verification failure rather than success.
        Ok(false) => Some(Err(AttestationError::Verification(format!(
            "archive file {} exists but its GitHub artifact attestation did not verify",
            file.display()
        )))),
        // The load-bearing fail-closed case (strict mode): once we know the
        // release attests inner files, a file with no attestation breaks the
        // "every file inside is attested" guarantee.
        Err(AttestationError::NoAttestations) => Some(Err(AttestationError::Verification(
            format!(
                "archive contains a file with no GitHub artifact attestation: {}",
                file.display()
            ),
        ))),
        // A real verification/network error propagates as-is (still fail-closed).
        Err(e) => Some(Err(e)),
    }
}

input.oldString:
/// Classify one inner file's attestation outcome into a terminal result for the
/// whole archive, or `None` to continue to the next file.
///
/// This is the single source of truth for the inner-file fail-closed policy;
/// both the streaming loop in [`verify_archive_aware_with_verifier`] and the
/// batched [`reduce_inner_outcomes`] used in tests route through it.
fn classify_inner_outcome(
    file: &Path,
    outcome: AttestationResult<bool>,
) -> Option<AttestationResult<bool>> {
    match outcome {
        Ok(true) => None,
        // The sigstore primitives never return Ok(false) today, but treat it as
        // a verification failure rather than success.
        Ok(false) => Some(Err(AttestationError::Verification(format!(
            "archive file {} exists but its GitHub artifact attestation did not verify",
            file.display()
        )))),
        // The load-bearing fail-closed case: a file with no attestation breaks
        // the "every file inside is attested" guarantee.
        Err(AttestationError::NoAttestations) => Some(Err(AttestationError::Verification(
            format!(
                "archive contains a file with no GitHub artifact attestation: {}",
                file.display()
            ),
        ))),
        // A real verification/network error propagates as-is (still fail-closed).
        Err(e) => Some(Err(e)),
    }
}

/// Batched equivalent of the streaming loop, used to pin the fail-closed policy
/// in tests without an async verifier. Returns `Ok(true)` only when every
/// outcome is `Ok(true)`.
#[cfg(test)]
fn reduce_inner_outcomes(
    files: &[PathBuf],
    outcomes: Vec<AttestationResult<bool>>,
) -> AttestationResult<bool> {
    for (file, outcome) in files.iter().zip(outcomes) {
        if let Some(terminal) = classify_inner_outcome(file, outcome) {
            return terminal;
        }
    }
    Ok(true)
}

