    #[tokio::test]
    async fn archive_aware_accepts_when_all_inner_files_attested() {
        let dir = tempfile::tempdir().unwrap();
        let archive = build_targz(
            dir.path(),
            &[
                TestEntry::File("bin/tool", b"binary-bytes"),
                TestEntry::File("README.md", b"docs"),
            ],
        );
        // Archive blob has NO attestation; every inner file is attested.
        let verifier = |p: &Path| {
            let p = p.to_path_buf();
            async move {
                if p.file_name().map(|n| n == "payload.tar.gz").unwrap_or(false) {
                    Err(AttestationError::NoAttestations)
                } else {
                    Ok(true)
                }
            }
        };
        let result = verify_archive_aware_with_verifier(&archive, verifier).await;
        assert!(matches!(result, Ok(true)), "expected Ok(true), got {result:?}");
    }

    #[tokio::test]
    async fn archive_aware_no_inner_attestations_falls_through() {
        // Regression guard: a release with NO attestations anywhere (archive or
        // inner files) MUST surface NoAttestations so the caller's existing
        // SLSA/unavailable fallback runs. It must NOT hard-fail — that would
        // break the vast majority of GitHub releases and re-introduce the
        // API-rate-limit problem this bridge exists to avoid.
        let dir = tempfile::tempdir().unwrap();
        let archive = build_targz(
            dir.path(),
            &[
                TestEntry::File("bin/tool", b"binary-bytes"),
                TestEntry::File("README.md", b"docs"),
            ],
        );
        let verifier = |_: &Path| async move { Err(AttestationError::NoAttestations) };
        let result = verify_archive_aware_with_verifier(&archive, verifier).await;
        assert!(
            matches!(result, Err(AttestationError::NoAttestations)),
            "no-attestation release must fall through, got {result:?}"
        );
    }

    #[tokio::test]
    async fn archive_aware_rejects_when_other_inner_file_unattested() {
