/// Verify a GitHub artifact attestation for a downloaded file, transparently
/// handling releases that attest each file *inside* an archive rather than the
/// archive blob itself.
///
/// Verification is **fail-closed** at every step:
///
/// 1. The archive blob (`archive_path`) is verified first — exactly the
///    pre-existing behavior. A successful verification (`Ok(true)`) is returned
///    immediately, and so is any error *other than* "no attestations exist for
///    this digest" ([`AttestationError::NoAttestations`]). In particular, if
///    attestations exist for the archive but fail to verify, that failure is
///    surfaced and the inner-file fallback never runs.
/// 2. Only when the archive has `NoAttestations` *and* `archive_path` is a
///    recognizable multi-file archive is it extracted to a temp directory and
///    every regular inner file required to have its own valid GitHub artifact
///    attestation under `(owner, repo)`. Directories and symlinks are ignored;
///    a nested archive is treated as an opaque regular file that must itself be
///    attested (it is not recursively unpacked). If **any** regular inner file
///    is unattested, or fails verification, the whole archive is rejected.
/// 3. Extraction failures and single-file/compressed payloads (`.gz`, `.xz`,
///    raw binaries) are not treated as archives here, so the original
///    `NoAttestations` result is returned and callers' existing SLSA/unavailable
///    fallbacks run unchanged.
///
/// This preserves archive-level verification while safely accepting releases
/// that only attest the files inside the archive.
pub async fn verify_attestation_or_archive_contents(
    archive_path: &Path,
    owner: &str,
    repo: &str,
    expected_workflow: Option<&str>,
    api_url: Option<&str>,
) -> AttestationResult<bool> {
    // Clone the borrowed args so the verifier closure (which returns a future
    // borrowing only its owned captures) can be reused across every inner file.
    let owner = owner.to_string();
    let repo = repo.to_string();
    let expected_workflow = expected_workflow.map(str::to_string);
    let api_url = api_url.map(str::to_string);
    verify_archive_aware_with_verifier(archive_path, |path: &Path| {
        let path = path.to_path_buf();
        let owner = owner.clone();
        let repo = repo.clone();
        let expected_workflow = expected_workflow.clone();
        let api_url = api_url.clone();
        async move {
            verify_attestation(
                &path,
                &owner,
                &repo,
                expected_workflow.as_deref(),
                api_url.as_deref(),
            )
            .await
        }
    })
    .await
}

/// Archive-aware verification core, generic over the per-file verifier so the
/// fail-closed ordering, archive detection, extraction, and "every inner file
/// must be attested" policy are unit-testable without touching the network.
///
/// The verifier is called on the archive blob first; then, only on
/// `NoAttestations` for a real archive, on every regular inner file. All inner
/// files must verify (`Ok(true)`) for the archive to be accepted.
async fn verify_archive_aware_with_verifier<F, Fut>(
    archive_path: &Path,
    mut verify: F,
) -> AttestationResult<bool>
where
    F: FnMut(&Path) -> Fut,
    Fut: std::future::Future<Output = AttestationResult<bool>>,
{
    let archive_outcome = verify(archive_path).await;

    // Fail closed: only consider inner files when the archive has NO
    // attestations at all. A genuine verification failure (attestations exist
    // but are invalid) must never trigger the fallback.
    if !matches!(archive_outcome, Err(AttestationError::NoAttestations)) {
        return archive_outcome;
    }

    // Only multi-file archives (tar*/zip/7z) can carry individually-attested
    // inner files. Single-file compressions (`.gz`, `.xz`, …) and raw binaries
    // are left to the caller's existing fallback path.
    let file_name = archive_path
        .file_name()
        .map(std::ffi::OsStr::to_string_lossy)
        .unwrap_or_default()
        .to_string();
    let format = TarFormat::from_file_name(&file_name);
    if !format.is_archive() {
        return archive_outcome;
    }

    // Bind the TempDir guard at function scope (not inside the match arm) so it
    // outlives the `verify` calls below — the extracted files live on disk under
    // it and the real verifier reads them.
    let (_tmp_guard, mut inner) = match extract_regular_files(archive_path, format) {
        Ok(pair) => pair,
        Err(e) => {
            debug!(
                "could not extract {} for inner-file attestation verification \
                 ({e}); skipping fallback",
                archive_path.display()
            );
            // Behavior-preserving: don't introduce a new hard failure for a
            // format/IO limitation. Return the original NoAttestations so the
            // caller's SLSA/unavailable logic runs unchanged.
            return archive_outcome;
        }
    };
    // An archive with no regular files cannot be meaningfully attested "per
    // file" — don't vacuously accept it.
    if inner.is_empty() {
        return archive_outcome;
    }
    // Deterministic probe selection (the rest of the policy keys off which file
    // is probed first, so sort to make it stable rather than OS read_dir order).
    inner.sort();

    // Detect whether this release attests inner files *at all* by probing a
    // single inner file. This keeps the fallback to O(1) extra API calls in the
    // common case — a release with no attestations anywhere — preserving the
    // rate-limit guarantee this bridge exists to maintain.
    //
    // - Probe is `Ok(true)` (or any non-`NoAttestations` result) → the release

